diagrams.d2:
direction: right
blocks: { label: "SpecBlock[]"; class: actor }
renderAll: { label: "renderAll\n(diagrams)" }
lint: { label: "lintSpec\nwarnings"; class: changed }
section: { label: "renderBlock\nper-type <section>" }
card: { label: "renderDiagramCard\n(recap shell)" }
rail: { label: "sidebar + progress rail" }
html: { label: "spec.html" }
blocks -> renderAll: collectSpecDiagrams
blocks -> lint
blocks -> section
section -> card: diagram blocks
blocks -> rail: chapters
section -> html
rail -> html

diagrams.mermaid:
flowchart LR
  blocks["SpecBlock[]"] -->|collectSpecDiagrams| renderAll["renderAll (diagrams)"]
  blocks --> lint["lintSpec warnings"]
  blocks --> section["renderBlock per-type section"]
  section -->|diagram blocks| card["renderDiagramCard (recap shell)"]
  blocks -->|chapters| rail["sidebar + progress rail"]
  section --> html["spec.html"]
  rail --> html
  classDef changed fill:#ffd43b,stroke:#f08c00,color:#1b1b1b,stroke-width:2px;
  classDef actor fill:#d0ebff,stroke:#4dabf7,color:#1b1b1b;
  class blocks actor;
  class lint changed;
